from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a fluent sentence that combines information from all provided triples."""
    if not triples:
        return ""

    # Helper functions for specific predicates
    def phrase(triple: Triple) -> str:
        # Normalise predicate, subject and object
        p = triple.predicate
        s = triple.subject
        # Strip surrounding quotes from objects for cleaner text
        o = triple.object.strip('\"')
        # Specific phrasing for known predicates
        if p == "almaMater":
            return f"{s} attended {o}"
        if p == "birthDate":
            return f"{s} was born on {o}"
        if p == "birthName":
            return f"{s}'s birth name is {o}"
        if p == "birthPlace":
            return f"{s} was born in {o}"
        if p == "dateOfRetirement":
            return f"{s} retired on {o}"
        if p == "occupation":
            return f"{s} worked as a {o}"
        if p == "status":
            return f"{s} is {o.lower()}"
        if p == "timeInSpace":
            return f"{s} spent {o} minutes in space"
        if p == "mission":
            return f"{s} flew on the {o} mission"
        if p == "selectedByNasa":
            return f"{s} was selected by NASA in {o}"
        if p == "deathDate":
            return f"{s} died on {o}"
        if p == "nationality":
            return f"{s} was a {o} national"
        if p == "servedAsChiefOfTheAstronautOfficeIn":
            return f"{s} served as chief of the Astronaut Office in {o}"
        if p == "title":
            return f"{s}'s title is {o}"
        if p == "ribbonAward":
            return f"{s} received the {o} ribbon award"
        if p == "operator":
            return f"{s} was operated by {o}"
        if p == "backupPilot":
            return f"The backup pilot of {s} was {o}"
        if p == "commander":
            return f"The commander of {s} was {o}"
        if p == "crewMembers":
            return f"The crew members of {s} include {o}"
        if p == "representative":
            return f"The representative of {s} is {o}"
        if p == "alternativeName":
            return f"{s} is also known as {o}"
        if p == "awards":
            return f"{s} received {o} awards"
        # Generic fallback
        return f"{s} {p} {o}"

    # Build phrases for each triple
    phrases = [phrase(t) for t in triples]

    # Combine phrases into a single coherent sentence with natural conjunctions
    if len(phrases) == 1:
        sentence = phrases[0] + "."
    else:
        # Join all but the last with commas, and prepend 'and' before the final phrase
        sentence = ", ".join(phrases[:-1]) + ", and " + phrases[-1] + "."
    return sentence

# EVOLVE-BLOCK-END
